<?php
namespace App\Modules\Hr\Lifecycle\Models;use App\Modules\Hr\Core\Traits\BelongsToLegalEntity;use App\Modules\Hr\Personnel\Models\HrEmployee;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;use Illuminate\Database\Eloquent\Relations\HasMany;
class HrOnboardingChecklist extends Model{use BelongsToLegalEntity;protected $fillable=['legal_entity_id','employee_id','application_id','title','starts_on','target_completion_on','status','completed_at','created_by'];protected function casts():array{return ['starts_on'=>'date','target_completion_on'=>'date','completed_at'=>'datetime'];}public function employee():BelongsTo{return $this->belongsTo(HrEmployee::class);}public function tasks():HasMany{return $this->hasMany(HrOnboardingTask::class,'checklist_id');}}
